                    groups: t.Sequence[str] = m.groups()

                    if isinstance(tokens, OptionalLStrip):
                        text = groups[0]
                        strip_sign = next(g for g in groups[2::2] if g is not None)

                        if strip_sign == "-":
                            stripped = text.rstrip()
                            newlines_stripped = text[len(stripped) :].count("\n")
